-- Legislacao full-site: ricardo-nunes / Prefeitura de Sao Paulo / legislacao_mandato_executivo
-- Completo provado escopado: leis municipais PMSP assinadas/promulgadas por Ricardo Nunes
-- Generated by scripts/generate-legislacao-ricardo-nunes-pmsp-completo-20260512.ts
-- Artifact: fonte interna de curadoria
-- ============================================
-- Fonte oficial: Prefeitura de Sao Paulo - Catalogo de Legislacao Municipal
-- Busca POST /busca e /busca/pg/N:
--   ano-inicial=16/05/2021
--   ano-final=12/05/2026
--   tipo[]=LEI
--
-- Coverage:
--   coverage_id    = ricardo-nunes-sp-prefeitura-completo-leis-municipais-2021-2026-cutoff-20260512
--   coverage_scope = inventario_completo_sp_prefeitura_leis_municipais_ricardo_nunes_2021_2026_cutoff_20260512
--
-- Filtro factual: paginas oficiais PMSP com numero, data, ementa,
-- formula "RICARDO NUNES, Prefeito do Municipio de Sao Paulo" e
-- "decretou e eu promulgo a seguinte lei".
-- Nao e inventario global da vida politica, nao cobre atos fora do Catalogo
-- PMSP, nao cobre decretos/portarias e nao toca autoria parlamentar.
--
-- Esta migration escreve somente em legislacao_mandato_executivo.
-- Esta migration NAO escreve em projetos_lei.
-- Esta migration NAO altera historico_politico.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  lme_total int;
  target_count int;
  other_lme_count int;
  mandato_count int;
  projetos_count int;
  seed_count int;
  duplicate_seed_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ricardo-nunes';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ricardo-nunes: candidato ausente neste banco local/CI minimo; seed LME PMSP pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO lme_total
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'ricardo-nunes-sp-prefeitura-completo-leis-municipais-2021-2026-cutoff-20260512';

  SELECT count(*) INTO other_lme_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND COALESCE(metadata->>'coverage_id', '') <> 'ricardo-nunes-sp-prefeitura-completo-leis-municipais-2021-2026-cutoff-20260512';

  IF lme_total NOT IN (0, 718) THEN
    RAISE EXCEPTION 'Pre-condicao ricardo-nunes: esperadas 0 rows atuais ou 718 rows alvo idempotentes em legislacao_mandato_executivo, encontradas %', lme_total;
  END IF;

  IF lme_total = 718 AND target_count <> 718 THEN
    RAISE EXCEPTION 'Pre-condicao ricardo-nunes: 718 rows existentes, mas apenas % com coverage_id alvo', target_count;
  END IF;

  IF other_lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao ricardo-nunes: % rows LME fora do coverage alvo; abortando para nao misturar lotes', other_lme_count;
  END IF;

  SELECT count(*) INTO projetos_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  IF projetos_count <> 1 THEN
    RAISE EXCEPTION 'Pre-condicao ricardo-nunes: projetos_lei mudou de 1 para %', projetos_count;
  END IF;

  SELECT count(*) INTO mandato_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Prefeito%' OR hp.cargo_canonico = 'Prefeito')
    AND UPPER(COALESCE(hp.estado, '')) = 'SP'
    AND (hp.cargo ILIKE '%São Paulo%' OR hp.cargo ILIKE '%Sao Paulo%' OR hp.observacoes ILIKE '%Prefeitura de São Paulo%' OR hp.observacoes ILIKE '%Prefeitura de Sao Paulo%')
    AND COALESCE(hp.periodo_inicio, 9999) <= 2026
    AND COALESCE(hp.periodo_fim, 9999) >= 2021;

  IF mandato_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao ricardo-nunes: mandato Prefeito/Sao Paulo compativel com 2021-2026 nao encontrado em historico_politico';
  END IF;
END $$;

