    ('lei_sancionada', 'municipal', 'SP', 'São Paulo', 'lei', '18.229', 2025, '2025-01-16', 'Desincorpora da classe dos bens de uso especial e transfere para a classe dos bens dominiais as áreas municipais que especifica; autoriza concessões administrativas de uso das áreas municipais que especifica; autoriza o Executivo a receber, em doação, o imóvel situado no Parque do Cocaia, para implantação de um posto de assistência médica; autoriza o Executivo a alienar, mediante doação com encargo, o imóvel que especifica; desincorpora da classe dos bens de uso comum do povo e transfere para a classe dos bens dominiais a área municipal localizada no Distrito de M’Boi Mirim, cuja alienação também é autorizada, na forma especificada; e dá providências.', 'RICARDO NUNES', 'titular', 'https://legislacao.prefeitura.sp.gov.br/leis/lei-18229-de-16-de-janeiro-de-2025', 'Prefeitura de São Paulo - Catálogo de Legislação Municipal', NULL, 'PMSP:LEI:18229:2025', '{"source":"Prefeitura de São Paulo - Catálogo de Legislação Municipal","data_real":true,"fluxo":"Legislacao full-site","slug":"ricardo-nunes","tabela_alvo":"legislacao_mandato_executivo","projetos_lei_mixed":false,"historico_politico_id_inferido_por_data":false,"curation_batch_id":"legislacao-ricardo-nunes-pmsp-completo-20260512","migration_version":"20260512190000","coverage_id":"ricardo-nunes-sp-prefeitura-completo-leis-municipais-2021-2026-cutoff-20260512","coverage_scope":"inventario_completo_sp_prefeitura_leis_municipais_ricardo_nunes_2021_2026_cutoff_20260512","coverage_status":"completo_escopado","coverage_public_status":"executive_complete","coverage_policy":"pmsp_catalogo_leis_municipais_prefeito_ricardo_nunes_v1","coverage_cutoff":"2026-05-12","source_artifact":"fonte interna de curadoria","recorte_publico":"leis municipais do Catálogo de Legislação Municipal da Prefeitura de São Paulo, tipo LEI, assinadas/promulgadas por Ricardo Nunes como Prefeito","fonte_oficial":"Prefeitura de São Paulo - Catálogo de Legislação M