    ('lei_sancionada', 'municipal', 'SP', 'São Paulo', 'lei', '18.062', 2023, '2023-12-28', 'Desincorpora da classe de bens de uso especial e transfere para a classe de bens dominiais área municipal situada no Distrito de Bela Vista, bem como autoriza a sua permuta por imóvel de propriedade particular; desincorpora área identificada no Anexo I desta Lei e autoriza sua alienação, mediante doação com encargos, à COHAB-SP ou à concessionária contratada pela COHAB-SP para a implantação de habitações; autoriza doação à COHAB-SP das áreas municipais e respectivas edificações integrantes dos conjuntos relacionados no Anexo II desta Lei; autoriza concessões administrativas de uso das áreas municipais que especifica, e dá outras providências.', 'RICARDO NUNES', 'titular', 'https://legislacao.prefeitura.sp.gov.br/leis/lei-18062-de-28-de-dezembro-de-2023', 'Prefeitura de São Paulo - Catálogo de Legislação Municipal', NULL, 'PMSP:LEI:18062:2023', '{"source":"Prefeitura de São Paulo - Catálogo de Legislação Municipal","data_real":true,"fluxo":"Legislacao full-site","slug":"ricardo-nunes","tabela_alvo":"legislacao_mandato_executivo","projetos_lei_mixed":false,"historico_politico_id_inferido_por_data":false,"curation_batch_id":"legislacao-ricardo-nunes-pmsp-completo-20260512","migration_version":"20260512190000","coverage_id":"ricardo-nunes-sp-prefeitura-completo-leis-municipais-2021-2026-cutoff-20260512","coverage_scope":"inventario_completo_sp_prefeitura_leis_municipais_ricardo_nunes_2021_2026_cutoff_20260512","coverage_status":"completo_escopado","coverage_public_status":"executive_complete","coverage_policy":"pmsp_catalogo_leis_municipais_prefeito_ricardo_nunes_v1","coverage_cutoff":"2026-05-12","source_artifact":"fonte interna de curadoria","recorte_publico":"leis municipais do Catálogo de Legislação Municipal da Prefeitura de São Paulo, tipo LEI, assinadas/promulgadas por Ricardo Nunes como Prefeito","fonte_oficial":"Prefeitura de São Paulo - Catálogo de Legislação Municipal