    ('lei_sancionada', 'municipal', 'SP', 'São Paulo', 'lei', '18.038', 2023, '2023-12-08', 'Altera a Lei nº 14.977, de 11 de setembro de 2009, que trata da Gratificação por Desempenho em Atividade Delegada aos integrantes da Polícia Militar e da Polícia Civil que exercem atividade municipal delegada ao Estado de São Paulo por força de convênio celebrado com o Município de São Paulo; a Lei nº 16.081, de 30 setembro de 2014, que institui a Diária Especial por Atividade Complementar (DEAC), possibilita a concessão de incentivos à atividade delegada nas regiões estratégicas e no período noturno, a serem pagos aos Policiais Militares e Civis que exercem atividade municipal delegada; dispõe sobre alterações na Lei nº 10.182, de 30 de outubro de 1986, e dá outras providências sobre gestão de servidores.', 'RICARDO NUNES', 'titular', 'https://legislacao.prefeitura.sp.gov.br/leis/lei-18038-de-8-de-dezembro-de-2023', 'Prefeitura de São Paulo - Catálogo de Legislação Municipal', NULL, 'PMSP:LEI:18038:2023', '{"source":"Prefeitura de São Paulo - Catálogo de Legislação Municipal","data_real":true,"fluxo":"Legislacao full-site","slug":"ricardo-nunes","tabela_alvo":"legislacao_mandato_executivo","projetos_lei_mixed":false,"historico_politico_id_inferido_por_data":false,"curation_batch_id":"legislacao-ricardo-nunes-pmsp-completo-20260512","migration_version":"20260512190000","coverage_id":"ricardo-nunes-sp-prefeitura-completo-leis-municipais-2021-2026-cutoff-20260512","coverage_scope":"inventario_completo_sp_prefeitura_leis_municipais_ricardo_nunes_2021_2026_cutoff_20260512","coverage_status":"completo_escopado","coverage_public_status":"executive_complete","coverage_policy":"pmsp_catalogo_leis_municipais_prefeito_ricardo_nunes_v1","coverage_cutoff":"2026-05-12","source_artifact":"fonte interna de curadoria","recorte_publico":"leis municipais do Catálogo de Legislação Municipal da Prefeitura de São Paulo, tipo LEI, assinadas/promulgadas por Ricardo Nunes como Prefeito","fonte_ofic