    ('lei_sancionada', 'municipal', 'SP', 'São Paulo', 'lei', '17.913', 2023, '2023-02-17', 'Dispõe sobre a criação do Quadro de Fiscalização de Posturas Municipais – QFPM, com plano de carreira, reenquadra os cargos e funções de Agente Vistor, do Quadro de Agentes Vistores – QAV, criado pela Lei nº 16.417, de 1º de abril de 2016, institui o respectivo regime de remuneração por subsídio e a Bonificação de Desempenho da Fiscalização; dispõe sobre a criação de cargos no Quadro dos Profissionais de Gestão Governamental – QPGG, nos termos da Lei nº 16.193, de 5 de maio de 2015, e altera a referida Lei; dispõe sobre a readequação do valor da Gratificação de Municipalização, instituída pela Lei nº 13.510, de 10 de janeiro de 2003, para os profissionais que especifica; inclui o art. 1º-A na Lei nº 16.011, de 11 de junho de 2014; dispõe sobre a alteração das Leis nº 16.414, de 1º de abril de 2016, e nº 17.841, de 19 de agosto de 2022; dispõe sobre a valorização dos plantões extras do Quadro da Saúde, e dá outras providências.', 'RICARDO NUNES', 'titular', 'https://legislacao.prefeitura.sp.gov.br/leis/lei-17913-de-17-de-fevereiro-de-2023', 'Prefeitura de São Paulo - Catálogo de Legislação Municipal', NULL, 'PMSP:LEI:17913:2023', '{"source":"Prefeitura de São Paulo - Catálogo de Legislação Municipal","data_real":true,"fluxo":"Legislacao full-site","slug":"ricardo-nunes","tabela_alvo":"legislacao_mandato_executivo","projetos_lei_mixed":false,"historico_politico_id_inferido_por_data":false,"curation_batch_id":"legislacao-ricardo-nunes-pmsp-completo-20260512","migration_version":"20260512190000","coverage_id":"ricardo-nunes-sp-prefeitura-completo-leis-municipais-2021-2026-cutoff-20260512","coverage_scope":"inventario_completo_sp_prefeitura_leis_municipais_ricardo_nunes_2021_2026_cutoff_20260512","coverage_status":"completo_escopado","coverage_public_status":"executive_complete","coverage_policy":"pmsp_catalogo_leis_municipais_prefeito_ricardo_nunes_v1","coverage_cutoff":"2026-05