DO $$
DECLARE
  seed_count int;
  duplicate_seed_count int;
BEGIN
  SELECT count(*) INTO seed_count FROM _seed_ricardo_nunes_pmsp_completo_lme;
  SELECT count(*) INTO duplicate_seed_count
  FROM (
    SELECT identificador_fonte
    FROM _seed_ricardo_nunes_pmsp_completo_lme
    GROUP BY identificador_fonte
    HAVING count(*) > 1
  ) duplicated;

  IF seed_count <> 718 THEN
    RAISE EXCEPTION 'Pre-condicao ricardo-nunes: seed tem % rows, esperado 718', seed_count;
  END IF;

  IF duplicate_seed_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao ricardo-nunes: seed tem % identificadores duplicados', duplicate_seed_count;
  END IF;
END $$;

WITH target AS (
  SELECT
    c.id AS candidato_id,
    seed.*,
    (
      SELECT hp.id
      FROM historico_politico hp
      WHERE hp.candidato_id = c.id
        AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
        AND (hp.cargo ILIKE '%Prefeito%' OR hp.cargo_canonico = 'Prefeito')
        AND UPPER(COALESCE(hp.estado, '')) = 'SP'
        AND (hp.cargo ILIKE '%São Paulo%' OR hp.cargo ILIKE '%Sao Paulo%' OR hp.observacoes ILIKE '%Prefeitura de São Paulo%' OR hp.observacoes ILIKE '%Prefeitura de Sao Paulo%')
        AND COALESCE(hp.periodo_inicio, 9999) <= seed.ano
        AND COALESCE(hp.periodo_fim, 9999) >= seed.ano
      ORDER BY hp.periodo_inicio DESC NULLS LAST, hp.id
      LIMIT 1
    ) AS historico_politico_id
  FROM candidatos c
  CROSS JOIN _seed_ricardo_nunes_pmsp_completo_lme seed
  WHERE c.slug = 'ricardo-nunes'
)
INSERT INTO legislacao_mandato_executivo (
  candidato_id,
  historico_politico_id,
  tipo_relacao,
  esfera,
  uf_norma,
  municipio_norma,
  tipo_norma,
  numero,
  ano,
  data_norma,
  ementa,
  signatario,
  autoridade_papel,
  fonte_primaria_url,
  fonte_primaria_titulo,
  fonte_tramitacao_url,
  identificador_fonte,
  metadata
)
SELECT
  target.candidato_id,
  target.historico_politico_id,
  target.tipo_relacao,
  target.esfera,
  target.uf_norma,
  target.municipio_norma,
  target.tipo_norma,
  target.numero,
  target.ano,
  target.data_norma::date,
  target.ementa,
  target.signatario,
  target.autoridade_papel,
  target.fonte_primaria_url,
  target.fonte_primaria_titulo,
  target.fonte_tramitacao_url,
  target.identificador_fonte,
  target.metadata
FROM target
WHERE NOT EXISTS (
    SELECT 1
    FROM legislacao_mandato_executivo lme
    WHERE lme.candidato_id = target.candidato_id
      AND lme.identificador_fonte = target.identificador_fonte
  );

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  scope_count int;
  metadata_count int;
  projetos_count int;
  missing_mandate_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ricardo-nunes';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ricardo-nunes: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO scope_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'ricardo-nunes-sp-prefeitura-completo-leis-municipais-2021-2026-cutoff-20260512'
    AND metadata->>'coverage_scope' = 'inventario_completo_sp_prefeitura_leis_municipais_ricardo_nunes_2021_2026_cutoff_20260512'
    AND signatario = 'RICARDO NUNES'
    AND autoridade_papel = 'titular';

  SELECT count(*) INTO metadata_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'ricardo-nunes-sp-prefeitura-completo-leis-municipais-2021-2026-cutoff-20260512'
    AND metadata->>'coverage_scope' = 'inventario_completo_sp_prefeitura_leis_municipais_ricardo_nunes_2021_2026_cutoff_20260512'
    AND metadata->>'coverage_status' = 'completo_escopado'
    AND metadata->>'coverage_public_status' = 'executive_complete'
    AND metadata->>'tabela_alvo' = 'legislacao_mandato_executivo'
    AND metadata->>'projetos_lei_mixed' = 'false';

  SELECT count(*) INTO missing_mandate_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'ricardo-nunes-sp-prefeitura-completo-leis-municipais-2021-2026-cutoff-20260512'
    AND historico_politico_id IS NULL;

  SELECT count(*) INTO projetos_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  IF total_count <> 718 THEN
    RAISE EXCEPTION 'Pos-apply ricardo-nunes: total LME esperado 718, encontrado %', total_count;
  END IF;

  IF scope_count <> 718 THEN
    RAISE EXCEPTION 'Pos-apply ricardo-nunes: esperadas 718 rows com coverage_id/scope/signatario alvo, encontradas %', scope_count;
  END IF;

  IF metadata_count <> 718 THEN
    RAISE EXCEPTION 'Pos-apply ricardo-nunes: esperadas 718 rows com metadata completo_escopado, encontradas %', metadata_count;
  END IF;

  IF missing_mandate_count <> 153 THEN
    RAISE EXCEPTION 'Pos-apply ricardo-nunes: % rows ficaram sem historico_politico_id, esperado 153 pelo historico_politico remoto atual', missing_mandate_count;
  END IF;

  IF projetos_count <> 1 THEN
    RAISE EXCEPTION 'Pos-apply ricardo-nunes: projetos_lei mudou de 1 para %', projetos_count;
  END IF;

  RAISE NOTICE 'Pos-apply ricardo-nunes PMSP completo: legislacao_mandato_executivo=% coverage_scope=% projetos_lei_preservado=%', total_count, scope_count, projetos_count;
END $$;
